final:
module RefModule (
    input clk,
    input reset,
    output reg [3:0] q
);

    // Counter logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset)
            q <= 4'b1111;
        else
            q <= q - 1;
    end

endmodule
